const items = [];
// "Look back in time" to get the prepared data
const inputData = $('Prepare jobs data').first().json; 

const startPage = parseInt(inputData.start_page, 10);
const endPage = parseInt(inputData.end_page, 10);
const job_id = inputData.job_id;

// This loop creates one item for each page
for (let i = startPage; i <= endPage; i++) {
  items.push({
    json: {
      pageIndex: i - 1, // 0-based for PDF.co
      pageNumber: i,    // 1-based for us
      job_id: job_id // Pass the job_id along!
    }
  });
}
return items;

