    ...order,
    job_id: job_id
  };
});

// 3. Return everything for the next nodes
return {
  job_update: jobUpdateData,
  work_orders_insert: workOrdersData,
  // Pass these through for the image loop
  job_id: job_id,
  start_page: webhookBody.start_page,
  end_page: webhookBody.end_page
};

